css_snippet.css_font_face_example:
@font-face {
  font-family: 'YourHeadlineFont';
  src: url('/fonts/YourHeadlineFont.woff2') format('woff2'),
       url('/fonts/YourHeadlineFont.woff') format('woff');
  font-weight: 700;
  font-style: normal;
  font-display: swap; /* Prevents FOIT, allows quick text display */
}

@font-face {
  font-family: 'YourBodyFont';
  src: url('/fonts/YourBodyFont.woff2') format('woff2');
  font-weight: 400;
  font-style: normal;
  font-display: optional; /* Use fallback if loading is too slow */
}

body {
  font-family: 'YourBodyFont', Arial, sans-serif;
  line-height: 1.6;
}

h1 {
  font-family: 'YourHeadlineFont', 'Georgia', serif;
}
